select c.*,m.name masterName, (case when NOW() < c.begin_date then '未开始' when NOW() >= c.begin_date and NOW() <= c.end_date then '进行中' when NOW() > c.end_date then '已结课' else '其他' end) status from clazz c left join emp m on c.master_id=m.id
c.name like concat('%',#{name},'%')
and c.begin_date >= #{begin}
and c.end_date <= #{end}
order by c.update_time desc
